import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import "./EventDetails.css";

const EventDetails = () => {
  const { id } = useParams();

  console.log("🔥 EventDetails loaded");

  const [event, setEvent] = useState(null);
  const [stats, setStats] = useState([]);

  const [form, setForm] = useState({
    first_name: "",
    last_name: "",
    email: "",
    telegram: ""
  });

  const [success, setSuccess] = useState("");

  // 🔥 загрузка события
  useEffect(() => {
  fetch(`http://localhost:5000/events/${id}`)
    .then(res => res.json())
    .then(data => {
      console.log("🔥 EVENT FROM API:", data);
      setEvent(data);
    });
}, [id]);

  // 🔥 загрузка статистики
  useEffect(() => {
    fetch(`http://localhost:5000/events/${id}/stats`)
      .then(res => res.json())
      .then(data => setStats(data))
      .catch(err => console.error(err));
  }, [id]);

  // 🔥 обработка формы
  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // 🔥 отправка регистрации
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const res = await fetch("http://localhost:5000/register", {
        method: "POST",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify({
          ...form,
          event_id: id
        })
      });

      const data = await res.json();

      if (res.ok) {
        setSuccess("✅ Ви успішно зареєструвалися!");
        setForm({
          first_name: "",
          last_name: "",
          email: "",
          telegram: ""
        });
      } else {
        setSuccess("❌ Помилка: " + data.error);
      }
    } catch {
      setSuccess("❌ Помилка з'єднання");
    }
  };

  if (!event) return <p className="loading">Завантаження...</p>;

  return (
    <div className="event-details">
      <div className="event-card">
        <h2>{event.title}</h2>
        <p>{event.description}</p>

        <div className="event-info">
          <span>📍 {event.location}</span>
          <span>📅 {new Date(event.date).toLocaleString()}</span>
        </div>
      </div>

      {/* 📊 Статистика */}
      <div className="stats">
        <h3>Статистика реєстрацій</h3>

        {stats.length > 0 ? (
          <ul>
            {stats.map((item, index) => (
              <li key={index}>
                {item.date} — {item.count} реєстрацій
              </li>
            ))}
          </ul>
        ) : (
          <p>Поки немає реєстрацій</p>
        )}
      </div>

      {/* 📝 Форма регистрации */}
      <div className="registration">
        <h3>Реєстрація на подію</h3>

        <form onSubmit={handleSubmit}>
          <input
            name="first_name"
            placeholder="Ім'я"
            value={form.first_name}
            onChange={handleChange}
            required
          />

          <input
            name="last_name"
            placeholder="Прізвище"
            value={form.last_name}
            onChange={handleChange}
            required
          />

          <input
            name="email"
            type="email"
            placeholder="Email"
            value={form.email}
            onChange={handleChange}
            required
          />

          <input
            name="telegram"
            placeholder="Telegram"
            value={form.telegram}
            onChange={handleChange}
            required
          />

          <button type="submit">Зареєструватися</button>
        </form>

        {success && <p className="success">{success}</p>}
      </div>
    </div>
  );
};

export default EventDetails;
